class Solution:
    def longestCommonPrefix(self, words, k):
        n = len(words)
        ans = []
        for i in range(n):
            remaining = words[:i] + words[i + 1:]
            if len(remaining) < k:
                ans.append(0)
                continue
            from itertools import combinations
            best = 0
            for combo in combinations(remaining, k):
                l = min(len(x) for x in combo)
                p = 0
                while p < l and all(x[p] == combo[0][p] for x in combo):
                    p += 1
                if p > best:
                    best = p
            ans.append(best)
        return ans

