class Solution:
    def longestCommonPrefix(self, words, k):
        n = len(words)
        if n <= k:
            return [0] * n
        children = [dict()]
        cnt = [0]
        depth = [0]
        for w in words:
            node = 0
            for ch in w:
                if ch not in children[node]:
                    children.append(dict())
                    cnt.append(0)
                    depth.append(depth[node] + 1)
                    children[node][ch] = len(children) - 1
                node = children[node][ch]
                cnt[node] += 1
        F = 0
        for v in range(len(cnt)):
            if cnt[v] > k and depth[v] > F:
                F = depth[v]
        exact_nodes_depth = {}
        for v in range(len(cnt)):
            if cnt[v] == k and depth[v] > F:
                exact_nodes_depth[v] = depth[v]
        members = {}
        if exact_nodes_depth:
            for i, w in enumerate(words):
                node = 0
                for ch in w:
                    node = children[node][ch]
                    if node in exact_nodes_depth:
                        members.setdefault(node, []).append(i)
        ans = [F] * n
        unresolved = set(range(n))
        order = sorted(exact_nodes_depth.keys(), key=lambda v: -exact_nodes_depth[v])
        for v in order:
            if not unresolved:
                break
            d = exact_nodes_depth[v]
            memset = set(members.get(v, []))
            newly = unresolved - memset
            for i in newly:
                ans[i] = d
            unresolved &= memset
        return ans

