var longestCommonPrefix = function(words, k) {
    const n = words.length;
    if (n <= k) return new Array(n).fill(0);
    const children = [new Map()];
    const cnt = [0];
    const depth = [0];
    for (const w of words) {
        let node = 0;
        for (const ch of w) {
            if (!children[node].has(ch)) {
                children.push(new Map());
                cnt.push(0);
                depth.push(depth[node] + 1);
                children[node].set(ch, children.length - 1);
            }
            node = children[node].get(ch);
            cnt[node]++;
        }
    }
    let F = 0;
    for (let v = 0; v < cnt.length; v++) {
        if (cnt[v] > k && depth[v] > F) F = depth[v];
    }
    const exactNodesDepth = new Map();
    for (let v = 0; v < cnt.length; v++) {
        if (cnt[v] === k && depth[v] > F) exactNodesDepth.set(v, depth[v]);
    }
    const members = new Map();
    if (exactNodesDepth.size > 0) {
        for (let i = 0; i < n; i++) {
            let node = 0;
            for (const ch of words[i]) {
                node = children[node].get(ch);
                if (exactNodesDepth.has(node)) {
                    if (!members.has(node)) members.set(node, []);
                    members.get(node).push(i);
                }
            }
        }
    }
    const ans = new Array(n).fill(F);
    let unresolved = new Set();
    for (let i = 0; i < n; i++) unresolved.add(i);
    const order = Array.from(exactNodesDepth.keys()).sort((a, b) => exactNodesDepth.get(b) - exactNodesDepth.get(a));
    for (const v of order) {
        if (unresolved.size === 0) break;
        const d = exactNodesDepth.get(v);
        const memset = new Set(members.get(v) || []);
        const newly = [];
        for (const i of unresolved) {
            if (!memset.has(i)) newly.push(i);
        }
        for (const i of newly) {
            ans[i] = d;
            unresolved.delete(i);
        }
        const remaining = new Set();
        for (const i of unresolved) {
            if (memset.has(i)) remaining.add(i);
        }
        unresolved = remaining;
    }
    return ans;
};
